INSERT INTO questions
  (id, specialty, stem, choices, correct_answer, explanation, telemetry, domain_name, subtopic, difficulty, "references", status, category)
VALUES
('authored-batch-r20-007', 'Pharmacology', 'A 4-year-old, 16-kg child undergoes flexible bronchoscopy under sedation for recurrent stridor. The pharynx is anesthetized with a 20% benzocaine topical spray before the procedure. Twenty minutes later the child becomes cyanotic and lethargic. The SpO2 reads 86% and does not improve despite a non-rebreather mask delivering 100% oxygen; an arterial blood gas drawn at the same time shows PaO2 240 mmHg, and the sample is described as chocolate-brown. Heart rate is 150/min, blood pressure is 92/58 mmHg. Which of the following is the most appropriate next pharmacologic intervention?', '[{"text":"Sodium thiosulfate 12.5 g IV with hydroxocobalamin","label":"A","correct":false,"rationale":"Incorrect: this is the cyanide-toxicity regimen, not a treatment for the methemoglobin produced by an oxidizing local anesthetic."},{"text":"Methylene blue 1-2 mg/kg IV over about 5 minutes","label":"B","correct":true,"rationale":"Correct: the chocolate-brown blood, SpO2 fixed near 85% despite a high PaO2, and benzocaine exposure indicate acquired methemoglobinemia, for which methylene blue reduces ferric heme back to the oxygen-binding ferrous state."},{"text":"20% intravenous lipid emulsion bolus over 2-3 minutes","label":"C","correct":false,"rationale":"Incorrect: lipid rescue treats local anesthetic systemic toxicity (cardiac arrest/seizures from amide agents), not the oxidized-hemoglobin state caused by benzocaine."},{"text":"High-dose ascorbic acid (vitamin C) IV as first-line therapy","label":"D","correct":false,"rationale":"Incorrect: ascorbic acid is a slow, second-line option reserved for patients in whom methylene blue is contraindicated, such as known G6PD deficiency."},{"text":"Immediate exchange transfusion","label":"E","correct":false,"rationale":"Incorrect: transfusion is a salvage measure for refractory or severe cases and is not the first-line response when methylene blue is available and not contraindicated."}]'::jsonb, 'B', 'Benzocaine and prilocaine are classic oxidizing agents that convert hemoglobin iron from the ferrous (Fe2+) to the ferric (Fe3+) state, producing methemoglobin that cannot carry oxygen. The hallmark is a saturation gap: pulse oximetry plateaus near 85% and fails to rise with supplemental oxygen, while co-oximetry confirms an elevated methemoglobin fraction and the blood appears chocolate-brown. First-line treatment is methylene blue 1-2 mg/kg IV over roughly 5 minutes, which acts as an electron donor via NADPH methemoglobin reductase; it is avoided in G6PD deficiency, where ascorbic acid is used instead.', '{}'::jsonb, 'Subspecialty Care', 'Local anesthetics - methemoglobinemia from benzocaine/prilocaine', 'medium', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK537317/","source":"Methemoglobinemia - StatPearls (NCBI Bookshelf)"}]'::jsonb, 'sme_review', 'Pharmacology'),
('authored-batch-r20-008', 'Pharmacology', 'A 58-year-old man with hypertension is intubated and mechanically ventilated in the ICU after an exploratory laparotomy. To facilitate sedation and limit opioid use, the team orders dexmedetomidine and the nurse administers a 1 mcg/kg loading dose over 5 minutes. Two minutes into the loading dose his blood pressure rises transiently from 138/80 to 176/98 mmHg, then over the next several minutes falls to 96/54 mmHg with a heart rate of 46/min. Which mechanism best explains the transient hypertension seen during the rapid loading dose?', '[{"text":"Central alpha-2A agonism in the locus coeruleus reducing norepinephrine release","label":"A","correct":false,"rationale":"Incorrect: central alpha-2A agonism produces the sustained sedation, sympatholysis, hypotension, and bradycardia that follow, not the early pressor response."},{"text":"Beta-1 adrenergic agonism increasing myocardial contractility","label":"B","correct":false,"rationale":"Incorrect: dexmedetomidine has no beta-agonist activity, and the accompanying bradycardia argues against beta-1 stimulation."},{"text":"Stimulation of peripheral postsynaptic alpha-2B receptors on vascular smooth muscle causing vasoconstriction","label":"C","correct":true,"rationale":"Correct: a rapid bolus produces a high plasma concentration that activates peripheral alpha-2B receptors on vascular smooth muscle, transiently raising systemic vascular resistance and blood pressure before central sympatholysis predominates."},{"text":"Baroreceptor-mediated reflex vasoconstriction triggered by the bradycardia","label":"D","correct":false,"rationale":"Incorrect: the hypertension precedes and is independent of the later bradycardia, and reflex responses cannot raise pressure while heart rate is falling."},{"text":"Inhibition of presynaptic norepinephrine reuptake raising synaptic catecholamine levels","label":"E","correct":false,"rationale":"Incorrect: dexmedetomidine is an agonist that suppresses norepinephrine release, not a reuptake inhibitor that would increase catecholamine availability."}]'::jsonb, 'C', 'Dexmedetomidine is a highly selective alpha-2 adrenergic agonist whose dominant clinical effect is central sympatholysis at the locus coeruleus, producing sedation, bradycardia, and hypotension. However, at the high transient plasma levels generated by a rapid loading dose it loses some selectivity and stimulates peripheral postsynaptic alpha-2B receptors on vascular smooth muscle, causing a brief rise in systemic vascular resistance and blood pressure. This biphasic pattern, an initial pressor phase followed by sustained hypotension and bradycardia, is minimized by giving the load over at least 10 minutes or omitting the bolus.', '{}'::jsonb, 'Subspecialty Care', 'Alpha-2 adrenergic agonists - dexmedetomidine hemodynamics', 'hard', '[{"url":"https://www.openanesthesia.org/keywords/dexmedetomidine/","source":"Dexmedetomidine - OpenAnesthesia"}]'::jsonb, 'sme_review', 'Pharmacology'),
('authored-batch-r20-009', 'Pharmacology', 'A 67-year-old woman is being separated from cardiopulmonary bypass after a mitral valve repair. After protocolized heparin reversal is begun with protamine, she abruptly develops systemic hypotension (BP 70/40 mmHg) while the surgeon notes the right ventricle becoming distended and poorly contractile. The pulmonary artery catheter shows pulmonary artery pressure rising from 28/14 to 62/34 mmHg, with a falling left atrial pressure. There is no rash, urticaria, or bronchospasm. Which of the following best characterizes this protamine reaction and its initial management?', '[{"text":"Type I reaction from rapid administration; simply slow the infusion and give a fluid bolus","label":"A","correct":false,"rationale":"Incorrect: a type I reaction is transient isolated hypotension from rapid injection, not the acute pulmonary hypertension and RV failure described here."},{"text":"Type II anaphylactoid reaction; treat immediately with epinephrine, antihistamines, and corticosteroids","label":"B","correct":false,"rationale":"Incorrect: the absence of urticaria, rash, and bronchospasm argues against an anaphylactoid (type II) mechanism, and the picture is dominated by pulmonary vasoconstriction rather than histamine-mediated features."},{"text":"Heparin rebound; administer an additional dose of protamine","label":"C","correct":false,"rationale":"Incorrect: heparin rebound causes recurrent bleeding from returning anticoagulant effect, not acute pulmonary hypertension, and giving more protamine could worsen this reaction."},{"text":"Type III reaction (catastrophic pulmonary vasoconstriction); stop protamine, support the right ventricle, and be prepared to reheparinize and return to bypass","label":"D","correct":true,"rationale":"Correct: acute pulmonary hypertension with right ventricular failure, systemic hypotension, and low left-heart filling without allergic features is the classic catastrophic type III reaction, managed by halting protamine, supporting the RV, and reheparinizing back onto bypass if needed."},{"text":"Protamine overdose causing its intrinsic anticoagulant effect; reverse with fresh frozen plasma","label":"E","correct":false,"rationale":"Incorrect: protamine''s weak intrinsic anticoagulant effect manifests as bleeding, not pulmonary vasoconstriction with RV failure, and FFP would not address this hemodynamic crisis."}]'::jsonb, 'D', 'Protamine reactions are classified into three types: type I is transient hypotension from rapid injection, type II is an anaphylactic/anaphylactoid response, and type III is catastrophic pulmonary vasoconstriction. The type III reaction is driven by heparin-protamine complexes triggering thromboxane and complement release, producing acute pulmonary hypertension, right ventricular distension and failure, low left-heart filling, and systemic hypotension. Management is to stop the protamine, support the failing right ventricle (inotropes, pulmonary vasodilators such as inhaled nitric oxide or prostacyclin), and be prepared to reheparinize and resume cardiopulmonary bypass or initiate mechanical support.', '{}'::jsonb, 'Subspecialty Care', 'Anticoagulant reversal - protamine reactions', 'hard', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK547753/","source":"Protamine - StatPearls (NCBI Bookshelf)"}]'::jsonb, 'sme_review', 'Pharmacology'),
('authored-batch-r20-010', 'Airway & ENT', 'A 64-year-old man with a T2 glottic squamous cell carcinoma is scheduled for transoral CO2 laser excision of the vocal cord lesion. He has well-controlled hypertension and a 40-pack-year smoking history. The trachea is intubated with a laser-resistant endotracheal tube, the cuff is filled with saline tinted with methylene blue, and the surgeon is about to begin lasing near the cords. The anesthetist is delivering an FiO2 of 0.45 with the remainder nitrous oxide, SpO2 is 100%, and end-tidal sevoflurane is at 1 MAC. Which adjustment most directly reduces the risk of an airway fire before the laser is activated?', '[{"text":"Increase FiO2 to 1.0 to build an oxygen reserve before the apneic portion of the case","label":"A","correct":false,"rationale":"Incorrect: a high FiO2 is the principal oxidizer driving airway fires, and at 100% oxygen a sustained flame ignites almost immediately when the laser strikes the tube or tissue."},{"text":"Deepen the anesthetic by raising end-tidal sevoflurane to 2 MAC","label":"B","correct":false,"rationale":"Incorrect: volatile agent depth governs anesthetic adequacy and hemodynamics, not the combustibility of the airway, and does nothing to lower the oxidizer concentration."},{"text":"Switch from the laser-resistant tube to a standard PVC endotracheal tube for a clearer surgical view","label":"C","correct":false,"rationale":"Incorrect: standard PVC tubes ignite readily and release toxic byproducts such as hydrochloric acid, so reverting to one would substantially raise, not lower, fire risk."},{"text":"Deflate the endotracheal tube cuff to prevent a pressure-related rupture during lasing","label":"D","correct":false,"rationale":"Incorrect: deflating the cuff allows oxygen-enriched gas to leak into the operative field and removes the saline-filled protective barrier, increasing rather than decreasing fire risk."},{"text":"Reduce FiO2 to 0.30 or less and replace the nitrous oxide with air (medical air/nitrogen)","label":"E","correct":true,"rationale":"Correct: both oxygen and nitrous oxide vigorously support combustion, so titrating FiO2 to 0.30 or below and using air as the balance gas minimizes the oxidizer concentration in the surgical field, the single most important fire-prevention step."}]'::jsonb, 'E', 'The fire triad in airway laser surgery is an oxidizer (oxygen and/or nitrous oxide), a fuel (the endotracheal tube and tissue), and an ignition source (the laser). The anesthetist controls the oxidizer: guidelines recommend keeping FiO2 below 0.30 when feasible and eliminating nitrous oxide, since both gases support combustion. Bench data show sustained flames at high FiO2 but no ignition at room-air oxygen concentrations, underscoring that lowering the oxidizer is the most effective preventive measure.', '{}'::jsonb, 'Subspecialty Care', 'Operating room / airway fire safety during laser laryngeal surgery', 'medium', '[{"url":"https://www.openanesthesia.org/keywords/laser-safety/","source":"Anesthesia for Laser Surgery - OpenAnesthesia"}]'::jsonb, 'sme_review', 'Airway & ENT'),
('authored-batch-r20-011', 'Airway & ENT', 'A 5-year-old, 20-kg boy returns to the emergency department 7 hours after an outpatient tonsillectomy with active oral bleeding and several episodes of swallowing and vomiting bright red blood. He is pale and anxious, heart rate 148, blood pressure 88/52, and capillary refill is 3 seconds. He last ate solid food this morning but has been swallowing blood since the bleeding began. Two large-bore IVs are placed and a 20 mL/kg balanced crystalloid bolus is started while blood is sent for type and crossmatch. Regarding induction and airway management for surgical control of the bleeding, which is the most appropriate plan?', '[{"text":"Perform a rapid sequence induction with two functioning suction setups, a styletted tube, and additional laryngoscopes immediately available","label":"A","correct":true,"rationale":"Correct: a bleeding tonsil patient is treated as a full stomach and is hypovolemic, so a rapid sequence induction after volume resuscitation, with redundant suction and backup airway equipment to manage blood obscuring the view, is the standard approach."},{"text":"Perform an inhalational induction by mask, allowing spontaneous ventilation throughout","label":"B","correct":false,"rationale":"Incorrect: this child already has IV access and a stomach full of swallowed blood, so a slow inhalational induction needlessly prolongs the time the airway is unprotected against aspiration."},{"text":"Delay surgery for 6 hours to satisfy standard fasting guidelines before any induction","label":"C","correct":false,"rationale":"Incorrect: ongoing hemorrhage is an emergency that cannot wait for elective fasting intervals, and the patient is already at full-stomach risk regardless of NPO time."},{"text":"Induce with a standard dose of propofol without prior volume resuscitation to speed airway control","label":"D","correct":false,"rationale":"Incorrect: this child is hypovolemic, and a full induction dose of propofol before resuscitation risks profound hypotension and cardiovascular collapse."},{"text":"Place a supraglottic airway device rather than an endotracheal tube to minimize airway stimulation","label":"E","correct":false,"rationale":"Incorrect: a supraglottic airway does not protect against aspiration of blood and gastric contents, which is precisely the hazard in a patient with a bleeding tonsillar fossa."}]'::jsonb, 'A', 'A child with post-tonsillectomy hemorrhage has two superimposed problems: hypovolemia from blood loss and a full stomach from swallowed blood. The patient should be volume-resuscitated before induction, and the airway secured by rapid sequence induction with cricoid pressure (or a controlled variant), an endotracheal tube, and at least two suction devices plus backup laryngoscopes because blood frequently obscures the laryngeal view. Hypoxemia is actually a more common adverse event than aspiration in this population, so preparation for a potentially difficult, blood-filled airway is essential.', '{}'::jsonb, 'Subspecialty Care', 'Post-tonsillectomy hemorrhage: aspiration risk and induction technique', 'easy', '[{"url":"https://pmc.ncbi.nlm.nih.gov/articles/PMC8749229/","source":"Pediatric Anesthesia Management for Post-Tonsillectomy Bleed: Current Status and Future Directions"}]'::jsonb, 'sme_review', 'Airway & ENT'),
('authored-batch-r20-012', 'Airway & ENT', 'A 3-year-old, 15-kg girl is recovering after an adenoidectomy. The trachea is extubated while she is in a light plane of anesthesia. Within seconds she develops paradoxical chest movement, tracheal tug, no audible air movement despite respiratory effort, and an absent capnography trace; SpO2 falls from 99% to 84% and continues to drop. A jaw thrust with continuous positive airway pressure using 100% oxygen and removal of oral secretions does not relieve the obstruction, and the SpO2 is now 72% with the heart rate falling to 70. She has a functioning peripheral IV. What is the most appropriate next intervention?', '[{"text":"Reattempt bag-mask ventilation with higher peak inspiratory pressures and continue suctioning the oropharynx","label":"A","correct":false,"rationale":"Incorrect: complete laryngospasm is glottic closure that does not open with higher mask pressures, and persisting with this approach wastes time while hypoxia and bradycardia worsen."},{"text":"Administer IV succinylcholine to break the laryngospasm, then ventilate with 100% oxygen","label":"B","correct":true,"rationale":"Correct: when CPAP and jaw thrust fail to relieve laryngospasm and the patient is becoming hypoxic and bradycardic, a small dose of succinylcholine (often with atropine for the bradycardia) relaxes the laryngeal muscles and allows ventilation."},{"text":"Perform an immediate emergency surgical cricothyrotomy","label":"C","correct":false,"rationale":"Incorrect: a surgical airway is a last resort reserved for a true cannot-intubate-cannot-oxygenate situation, whereas laryngospasm in a child with IV access is almost always broken pharmacologically first."},{"text":"Give nebulized racemic epinephrine and IV dexamethasone for presumed post-extubation airway edema","label":"D","correct":false,"rationale":"Incorrect: nebulized epinephrine and steroids treat subglottic edema/croup over minutes to hours and do nothing for the acute glottic closure of laryngospasm in this time frame."},{"text":"Reintubate the trachea immediately using direct laryngoscopy without administering any medication","label":"E","correct":false,"rationale":"Incorrect: attempting laryngoscopy against tightly closed, unrelaxed cords is difficult and traumatic, and instrumenting the larynx can deepen the spasm rather than relieve it."}]'::jsonb, 'B', 'Laryngospasm is sustained reflex glottic closure, most common at light planes during induction or emergence and especially after airway surgery in young children. First-line management is removing the stimulus, applying CPAP with 100% oxygen, and a firm jaw thrust (Larson maneuver). When these fail and oxygenation deteriorates with developing bradycardia, succinylcholine is the definitive treatment to relax the laryngeal musculature; atropine is given alongside to treat the hypoxia-related bradycardia, and intramuscular succinylcholine (3-4 mg/kg) is used if no IV is available.', '{}'::jsonb, 'Subspecialty Care', 'Post-extubation laryngospasm: stepwise management', 'hard', '[{"url":"https://www.openanesthesia.org/keywords/laryngospasm/","source":"Laryngospasm - OpenAnesthesia"}]'::jsonb, 'sme_review', 'Airway & ENT');
